content.css:
.kpi-card {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  width: 100%;
  height: 100%;
  padding: 8px;
  box-sizing: border-box;
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  overflow: hidden;
}
.kpi-label {
  font-size: 12px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 4px;
  text-align: center;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 100%;
}
.kpi-value {
  font-size: 32px;
  font-weight: 700;
  line-height: 1.1;
  text-align: center;
  white-space: nowrap;
}
.kpi-delta {
  font-size: 13px;
  font-weight: 600;
  margin-top: 4px;
  text-align: center;
  white-space: nowrap;
}
.kpi-sparkline {
  width: 80%;
  margin-top: 8px;
  flex-shrink: 0;
}
.kpi-sparkline svg {
  display: block;
  width: 100%;
}
